INSERT INTO "public"."interaction_history" ("id", "student_id", "subject", "student_answer", "ai_score", "ai_feedback", "status", "created_at") VALUES (5, 'STU-084', 'Science', 'Ilanga liphuma empumalanga liyoshona entshonalanga.', 10, 'Yindaba yokudla ngempela, ilanga liliphuma empumalanga liyoshona entshonalanga. Uyadlala kahle ngempela!', 'Approved', '2026-06-14 19:33:33.508102'), (11, 'STU-085', 'Science', 'Ilanga liphuma empumalang liyoshona entshonalanga.', 10, 'Uyihambe kahle, uthule ukuthi ilanga liphuma empumalanga liyoshona entshonalanga. Uyachazisa ngqo kanambambili ukuphuma nokushona kwelanga.', 'Approved', '2026-06-14 20:33:51.099592'), (12, 'STU-085', 'Science', 'Ilanga liphuma eningizimi liyoshona entshonalanga.', 10, 'Uthule ulungile, ilanga liphuma eningizimu liyashona entshonalanga. Uyasebenza kakhulu!', 'Approved', '2026-06-14 20:47:29.69259'), (13, 'STU-085', 'Science', 'Ilanga liphuma eningizimi liyoshona empumalanga.', 10, 'Uyaphinda kahle, ilanga liliphuma eningizimu lishone empumalanga. Uyasebenza kahle!', 'Approved', '2026-06-14 20:49:15.177557'), (14, 'STU-085', 'Science', 'Ilanga liphuma enyakatho liyoshona eningizimu.', 0, 'Uchwepeshe ngempela, ilanga liphuma emazantsi lishona enyakatho, akukho liphume enyakatho liyoshone eningizimu.', 'Flagged for Teacher Review', '2026-06-14 21:02:15.316759'), (15, 'STU-085', 'Science', 'Ilanga liphuma enyakatho liyoshona eningizimu.', 0, 'Uphawu lwakho ngokuphuma kwenyakatho kuyahluka, ilanga liphuma empumalanga lishona eningizimu.', 'Flagged for Teacher Review', '2026-06-14 21:38:53.985346'), (16, 'STU-084', 'Science', 'Ilanga liphuma empumalanga liyoshona entshonalanga.', 10, 'Uyacopheleleyi ngempela, ilanga liliphuma empumalanga lishone entshonalanga. Uyazibona izinto zesayensi ngendlela eyiyoqobo.', 'Approved', '2026-06-15 06:45:07.952249'), (17, 'STU-084', 'Science', 'Ilanga liphuma empumalanga liyoshona entshonalanga.', 10, 'Uyaphinda ngokwazi ukuphuma kwelanga, kanti futhi uthatha nthaka ngokwazi shona kwelanga. Ingane yakho iyaphumelela!', 'Approved', '2026-06-15 07:02:16.931142'), (18, 'STU-084', 'Science', 'Ilanga liphuma empumalanga loshona empumalanga.', 0, 'Uphawu lwakho lwempumelelo lungafanele kulandelwa ukwazi lokuthi ilanga liphuma empumalanga lishone entshonalanga. Uphawu lwakho lungasho ilanga liphuma empumalanga lishona empumalanga, lokho kukhona ukwehluleka kubukwa kwempumelelo yempilo yethu.', 'Flagged for Teacher Review', '2026-06-15 07:12:34.763132');